            'body{cursor:crosshair;background:radial-gradient(circle at 18% 20%,color-mix(in srgb,var(--accent),transparent 76%),transparent 24%),var(--bg)}.trail-section{min-height:100dvh;position:relative;display:grid;place-items:center;text-align:center;padding:90px 24px;overflow:hidden}.trail-title{position:relative;z-index:6}.trail-title h1{font-size:clamp(46px,9vw,140px);line-height:.84;letter-spacing:-.075em;margin:12px 0;text-transform:uppercase}.trail-title p{max-width:680px;margin:0 auto 24px;color:var(--muted);font-size:19px;line-height:1.55}.touch-note{color:var(--muted);font-size:13px}.trail-img{position:fixed;left:0;top:0;z-index:4;width:clamp(160px,21vw,340px);aspect-ratio:4/5;border-radius:26px;overflow:hidden;pointer-events:none;opacity:0;transform:translate(-50%,-50%) scale(.75) rotate(0deg);box-shadow:0 28px 92px rgba(0,0,0,.48);border:1px solid var(--line)}.trail-media{width:100%;height:100%;object-fit:cover;background-size:cover;background-position:center}.link-section{min-height:100dvh;padding:100px max(20px,7vw);display:grid;grid-template-columns:.8fr 1.2fr;gap:42px;align-items:center;border-top:1px solid var(--line)}.link-copy h2{font-size:clamp(34px,5vw,76px);line-height:.92;letter-spacing:-.06em;margin:12px 0}.link-copy p{color:var(--muted);line-height:1.6;font-size:18px}.trail-links{display:grid;gap:12px}.trail-link{position:relative;display:flex;align-items:center;justify-content:space-between;gap:20px;padding:26px 30px;border:1px solid var(--line);border-radius:24px;text-decoration:none;background:rgba(255,255,255,.055);overflow:hidden;transition:transform .25s,border-color .25s,background .25s}.trail-link::before{content:"";position:absolute;inset:0;background:linear-gradient(90deg,color-mix(in srgb,var(--accent),transparent 84%),transparent);transform:translateX(-100%);transition:transform .35s}.trail-link:hover{transform:translateX(12px);border-color:var(--accent);background:rgba(255,255,255,.085)}.trail-link:hover::before{transform:translateX(0)}.trail-link span,.trail-link strong{position:relative;z-index:1}.trail-link span{color:var(--accent);font-size:12px;font-weight:900;letter-spacing:.14em;text-transform:uppercase}.trail-link strong{font-size:clamp(22px,3vw,38px);letter-spacing:-.035em}.mobile-strip{display:none;gap:12px;overflow:auto;padding:18px}.mobile-strip .trail-img{position:relative;opacity:1;transform:none;left:auto;top:auto;flex:0 0 210px}.final-cta{text-align:center;padding:90px 24px}footer{border-top:1px solid var(--line);padding:28px;text-align:center;color:var(--muted);font-size:12px}@media(max-width:820px){body{cursor:auto}.trail-section{min-height:74dvh}.trail-img{display:none}.mobile-strip{display:flex}.mobile-strip .trail-img{display:block}.link-section{grid-template-columns:1fr;padding:70px 18px}.trail-link{display:block}.trail-link strong{display:block;margin-top:8px}.trail-title h1{font-size:clamp(46px,16vw,86px)}}';
        var body = '<div class="wm-brand">' + escapeHTML(opts.logoText) + '</div>' + hidden + '<section class="trail-section" id="trailSection"><div class="trail-title"><div class="wm-kicker">Image Trail Campaign</div><h1>' + splitHeadline(opts.headline) + '</h1><p>' + escapeHTML(opts.subtitle) + '</p><a class="wm-cta" href="' + escapeAttr(safeUrl(opts.url)) + '">' + escapeHTML(opts.cta) + '</a><p class="touch-note">Mueve el cursor o toca la pantalla para lanzar la estela visual.</p></div></section><div class="mobile-strip">' + hidden.replace(/trail-img/g, 'trail-img mobile-card') + '</div><section class="link-section"><div class="link-copy"><div class="wm-kicker">Link trail</div><h2>Una estela para cada decision</h2><p>Los enlaces pueden activar rastro visual y dirigir a compra, reserva o lead.</p></div><div class="trail-links">' + links + '</div></section><section class="final-cta"><a class="wm-cta" href="' + escapeAttr(safeUrl(opts.url)) + '">' + escapeHTML(opts.cta) + '</a></section><footer>' + escapeHTML(opts.logoText) + ' - Image Trail final viewer</footer>';
        var scripts = '<script>(function(){var imgs=Array.prototype.slice.call(document.querySelectorAll("body>.trail-img")),idx=0,lastX=0,lastY=0,minDist=34/((' + opts.intensity.toFixed(2) + ')+.4);function show(x,y){var dx=x-lastX,dy=y-lastY;if(Math.hypot(dx,dy)<minDist)return;lastX=x;lastY=y;var img=imgs[idx%imgs.length];idx++;img.style.opacity="1";img.style.left=x+"px";img.style.top=y+"px";img.style.transform="translate(-50%,-50%) scale(1) rotate("+((Math.random()-.5)*18)+"deg)";img.animate([{opacity:1,transform:img.style.transform},{opacity:0,transform:"translate(-50%,-50%) scale(.78) rotate("+((Math.random()-.5)*24)+"deg)"}],{duration:Math.round(780/(Math.max(.4,' + opts.speed.toFixed(2) + '))),easing:"cubic-bezier(.16,1,.3,1)",fill:"forwards"});}document.addEventListener("mousemove",function(e){show(e.clientX,e.clientY)});document.addEventListener("touchmove",function(e){if(e.touches[0])show(e.touches[0].clientX,e.touches[0].clientY)},{passive:true});document.querySelectorAll(".trail-link").forEach(function(a,i){a.addEventListener("mouseenter",function(){var r=a.getBoundingClientRect();for(var n=0;n<5;n++)setTimeout(function(){show(r.left+Math.random()*r.width,r.top+Math.random()*r.height)},n*55)})});})();<\/script>';
        return baseHead('Image Trail Campaign', opts) + css + closeDoc(body, scripts);
