    function buildFlipCards(mediaList, rawOpts) {
        var opts = normalizeOptions(rawOpts);
        var titles = ['Brand', 'Product', 'Offer', 'Proof', 'Event', 'CTA'];
        var cards = titles.map(function(title, i) {
            var front = mediaAt(mediaList, i * 2);
            var back = mediaAt(mediaList, i * 2 + 1);
            return '<article class="flip-card" tabindex="0"><div class="flip-inner"><div class="flip-face flip-front">' + bgLayer(front, 'flip-media') + '<div class="flip-shade"></div><div class="flip-copy"><span>0' + (i + 1) + '</span><h3>' + escapeHTML(i === 0 ? opts.headline : title) + '</h3></div></div><div class="flip-face flip-back">' + bgLayer(back, 'flip-media') + '<div class="flip-shade back"></div><div class="flip-copy"><span>' + escapeHTML(opts.logoText) + '</span><h3>' + escapeHTML(opts.cta) + '</h3><p>' + escapeHTML(opts.subtitle) + '</p></div></div></div></article>';
        }).join('');
        var css = baseCSS(opts) +
            '.hero{min-height:82dvh;display:grid;place-items:center;text-align:center;padding:80px 24px;background:radial-gradient(circle at 50% 14%,color-mix(in srgb,var(--accent),transparent 74%),transparent 30%)}.hero h1{font-size:clamp(42px,7vw,96px);line-height:.92;letter-spacing:-.06em;margin:12px 0}.hero p{max-width:720px;margin:0 auto 24px;color:var(--muted);font-size:19px;line-height:1.58}.cards-wrap{padding:24px max(18px,4vw) 110px}.cards-head{display:flex;align-items:end;justify-content:space-between;gap:20px;margin-bottom:24px}.cards-head h2{font-size:clamp(30px,4.6vw,66px);line-height:.94;letter-spacing:-.055em;margin:0}.cards-head p{max-width:560px;color:var(--muted);line-height:1.55}.flip-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:22px}.flip-card{perspective:1200px;min-height:430px;border-radius:30px;outline:0}.flip-inner{position:relative;width:100%;height:100%;min-height:430px;transform-style:preserve-3d;transition:transform .85s cubic-bezier(.16,1,.3,1)}.flip-card:hover .flip-inner,.flip-card.flipped .flip-inner,.flip-card:focus .flip-inner{transform:rotateY(180deg)}.flip-face{position:absolute;inset:0;border-radius:30px;overflow:hidden;border:1px solid var(--line);backface-visibility:hidden;display:flex;align-items:end;padding:26px;box-shadow:0 30px 100px rgba(0,0,0,.38)}.flip-back{transform:rotateY(180deg)}.flip-media{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;background-size:cover;background-position:center;filter:saturate(.98) brightness(.7)}.flip-shade{position:absolute;inset:0;background:linear-gradient(to top,rgba(0,0,0,.88),transparent 64%)}.flip-shade.back{background:linear-gradient(135deg,rgba(0,0,0,.88),color-mix(in srgb,var(--accent),transparent 68%))}.flip-copy{position:relative;z-index:2}.flip-copy span{color:var(--accent);font-size:12px;font-weight:900;letter-spacing:.14em;text-transform:uppercase}.flip-copy h3{font-size:clamp(28px,3.5vw,48px);line-height:.95;margin:8px 0}.flip-copy p{color:var(--muted);line-height:1.55;max-width:34ch}.instructions{margin-top:18px;color:var(--muted);font-size:13px;text-align:center}.final-cta{text-align:center;padding:90px 24px}footer{border-top:1px solid var(--line);padding:28px;text-align:center;color:var(--muted);font-size:12px}@media(max-width:980px){.flip-grid{grid-template-columns:1fr 1fr}}@media(max-width:640px){.cards-head{display:block}.flip-grid{grid-template-columns:1fr}.flip-card,.flip-inner{min-height:440px}.cards-wrap{padding:20px 16px 70px}}';
        var body = '<div class="wm-brand">' + escapeHTML(opts.logoText) + '</div><section class="hero"><div><div class="wm-kicker">Flip Cards Product Grid</div><h1>' + splitHeadline(opts.headline) + '</h1><p>' + escapeHTML(opts.subtitle) + '</p><a class="wm-cta" href="' + escapeAttr(safeUrl(opts.url)) + '">' + escapeHTML(opts.cta) + '</a></div></section><main class="cards-wrap"><div class="cards-head"><h2>Anverso y reverso claros</h2><p>Slots pares para front, impares para back. Imagenes y videos funcionan en ambas caras.</p></div><section class="flip-grid">' + cards + '</section><p class="instructions">Hover en desktop. Tap en movil. El export contiene solo esta experiencia final.</p></main><section class="final-cta"><a class="wm-cta" href="' + escapeAttr(safeUrl(opts.url)) + '">' + escapeHTML(opts.cta) + '</a></section><footer>' + escapeHTML(opts.logoText) + ' - Flip Cards final viewer</footer>';
        var scripts = '<script>(function(){document.querySelectorAll(".flip-card").forEach(function(card){card.addEventListener("click",function(){card.classList.toggle("flipped")});card.addEventListener("keydown",function(e){if(e.key==="Enter"||e.key===" "){e.preventDefault();card.classList.toggle("flipped")}})});})();<\/script>';
        return baseHead('Flip Cards Product Grid', opts) + css + closeDoc(body, scripts);
    }

    register({ id: 'text-mask-reveal', name: 'Text Mask Reveal', icon: 'TM', family: 'Hero / Campaign', description: 'Hero con mascara de texto, scroll reveal y media imagen/video de fondo.', sourceFile: 'text-mask.html', mediaMap: 'Slot 1 fondo reveal. Slot 2 textura del texto si es imagen.', build: buildTextMask });
